def longest_common_prefix(strings):
    """Returns the longest common prefix of a list of strings."""
    if not strings:
        return ''

    min_str = min(strings, key=len)
    for i, char in enumerate(min_str):
        for other in strings:
            if other[i] != char:
                return min_str[:i]
    return min_str
